SELECT IIf([Sales Line.Document Type]=1,"SALES",IIf([Sales Line.Document Type]=5,"RETURNS","")) AS DocumentType, [Sales Line].Type, [Sales Line].No_, [Sales Line].[Customer Order Ref_], [Sales Line].Reference, [Sales Line].[Gen_ Bus_ Posting Group], [Sales Line].[VAT Bus_ Posting Group], [Sales Header].[Customer Posting Group], [Sales Line].[Unit of Measure], [Sales Line].[Constant Variable Code], [Sales Line].[Assortment Code], [Sales Line].[Delete Reason], [Sales Line].[Sales_Purchase Status Code], [Sales Line].[Sales_Purchase Status - Item], [Sales Line].[Delete Date], [Sales Line].[Customer Price Group], [Sales Line].[Average Unit Price], [Sales Header].[Order Date], [Sales Header].[Subject 1], Salesperson_Purchaser_2.Name AS Subject1Name, [Sales Header].[Subject 2], Salesperson_Purchaser_3.Name AS Subject2Name, [Sales Header Extension].[Subject 3], Salesperson_Purchaser_4.Name AS Subject3Name, [Sales Header Extension].[Subject 4], Salesperson_Purchaser_5.Name AS Subject4Name, Salesperson_Purchaser_1.Code AS CapozonaCodice, Salesperson_Purchaser_1.Name AS Capozona, [Sales Header].[Salesperson Code], Salesperson_Purchaser.Name AS Salesperson, [Sales Line].[Constant Variable Code] AS ColorCode, [Sales Header].[Bill-to Customer No_], [Sales Header].[Bill-to Name], [Sales Header].[Sell-to Customer No_], [Sales Header].[Securities Received], [Sales Line].[Document No_], [Sales Line].[Line No_], IIf([Order Type]=1,"Riass.",IIf([order type]=2,"Pronto",IIf([order type]=3,"Stock",IIf([order type]=4,"Sost.",IIf([order type]=0,"Progr",IIf([order type]=5,"PreSeason",IIf([order type]=17,"Commerciale",IIf([order type]=18,"Selection","?")))))))) AS OrderType, Format(Month([Order date]),"00") & "/" & IIf(Day([order date])<11,"1",IIf(Day([order date])<21,"2","3")) AS OrderPeriod, IIf([Sales Line.document type]=1,Val([No_ of Pairs]),-Val([No_ of Pairs])) AS PairsSold, IIf([Sales Line.document type]=1,Val([Quantity]),-Val([Quantity])) AS QuantitySold, [Sales Line].[Currency Code], IIf([Sales Line.document type]=1,(Val([Line Amount])-Val([Inv_ Discount Amount])),-(Val([Line Amount])-Val([Inv_ Discount Amount]))) AS ValueSold, Val([Quantity Shipped]) AS QuantityShipped, IIf(Val([quantity])>0,Val([quantity shipped])/Val([quantity])*Val([no_ of pairs]),0) AS PairsShipped, IIf(Val([quantity])>0,Val([quantity shipped])/Val([quantity])*[ValueSold],0) AS ValueShipped, IIf([Sales Line.document type]=1,Val([Sales Line.Quantity Invoiced]),0) AS QuantityInvoiced, IIf([Sales Line.document type]=1,IIf(Val([Sales Line.quantity])>0,Val([Sales Line.quantity invoiced])/Val([Sales Line.quantity])*Val([Sales Line.no_ of pairs]),0),0) AS PairsInvoiced, IIf([Sales Line.document type]=1,IIf(Val([Sales Line.quantity])>0,Val([Sales Line.quantity invoiced])/Val([Sales Line.quantity])*[ValueSold],0),0) AS ValueInvoiced, IIf(Val([quantity])>0,Val([Return Qty_ Received])/Val([quantity])*[ValueSold],0) AS ValueReturned, -Val([Return Qty_ Received]) AS QuantityReturned, IIf(Val([quantity])>0,-Val([Return Qty_ Received])/Val([quantity])*Val([no_ of pairs]),0) AS PairsReturned, IIf([Sales Line.document type]=5,-Val([Sales Line.Quantity Invoiced]),0) AS QuantityCredited, IIf([Sales Line.document type]=5,IIf(Val([Sales Line.quantity])>0,-Val([Sales Line.quantity invoiced])/Val([Sales Line.quantity])*Val([Sales Line.no_ of pairs]),0),0) AS PairsCredited, IIf([Sales Line.document type]=5,IIf(Val([Sales Line.quantity])>0,Val([Sales Line.quantity invoiced])/Val([Sales Line.quantity])*[ValueSold],0),0) AS ValueCredited, Val([Subject 1 Commission _]) AS ProvvigioneSoggetto1, Val([Subject 2 Commission _]) AS ProvvigioneSoggetto2, Val([Subject 3 Commission _]) AS ProvvigioneSoggetto3, Val([Subject 4 Commission _]) AS ProvvigioneSoggetto4, Val([Area Manager Commission _]) AS ProvvigioneCapozona, Val([salesperson commission _]) AS ProvvigioneAgente, [Sales Line].[Return Reason Code] AS ReturnReasonCode, [Sales Header].[Ship-to Code], [Sales Header].[Ship-to Name] AS ClienteSpedizione, [Sales Header].[Ship-to Name 2] AS ClienteSpedizione2, [Sales Header].[Ship-to Address] AS IndirizzoSpedizione, [Sales Header].[Ship-to Address 2] AS IndirizzoSpedizione2, [Sales Header].[Ship-to City] AS CittaSpedizione, [Sales Header].[Ship-to Post Code] AS CodicePostaleSpedizione, [Sales Header].[Ship-to County] AS CountySpedizione, [Sales Line].[Requested Delivery Date], IIf(IsNull([qsoloVend-DatiBolleAperteRilasciate.order no_]),0,[PaiaInBollaTotale]) AS PairsReadyForShippingTotale, IIf(IsNull([qsoloVend-DatiBolleAperteRilasciate.order no_]),0,[quantitainbollatotale]) AS QuantityReadyForShippingTotale, IIf(IsNull([qsoloVend-DatiBolleAperteRilasciate.order no_]),0,IIf(Val([quantity])>0,Nz([quantitainbollatotale])/Val([quantity])*[ValueSold],0)) AS ValueReadyForShippingTotale, IIf(IsNull([qsoloVend-DatiBolleAperteRilasciate.order no_]),0,[PaiaInBollaRilasciate]) AS PairsReadyForShippingRilasciate, IIf(IsNull([qsoloVend-DatiBolleAperteRilasciate.order no_]),0,[quantitainbollarilasciate]) AS QuantityReadyForShippingRilasciate, IIf(IsNull([qsoloVend-DatiBolleAperteRilasciate.order no_]),0,IIf(Val([quantity])>0,Nz([quantitainbollarilasciate])/Val([quantity])*[ValueSold],0)) AS ValueReadyForShippingRilasciate, IIf(IsNull([qsoloVend-DatiBolleAperteRilasciate.order no_]),0,[PaiaInBollaAperte]) AS PairsReadyForShippingAperte, IIf(IsNull([qsoloVend-DatiBolleAperteRilasciate.order no_]),0,[quantitainbollaaperte]) AS QuantityReadyForShippingAperte, IIf(IsNull([qsoloVend-DatiBolleAperteRilasciate.order no_]),0,IIf(Val([quantity])>0,Nz([quantitainbollaaperte])/Val([quantity])*[ValueSold],0)) AS ValueReadyForShippingAperte, IIf(IsNull([qsoloVend-DatiBolleAperteRilasciate.order no_]),0,[PaiaInBollaDaInviareWMSps]) AS PairsReadyForShippingDaInviareWMSps, IIf(IsNull([qsoloVend-DatiBolleAperteRilasciate.order no_]),0,[quantitainbollaDaInviareWMSps]) AS QuantityReadyForShippingDaInviareWMSps, IIf(IsNull([qsoloVend-DatiBolleAperteRilasciate.order no_]),0,IIf(Val([quantity])>0,Nz([quantitainbollaDaInviareWMSps])/Val([quantity])*[ValueSold],0)) AS ValueReadyForShippingDaInviareWMSps, IIf(IsNull([qsoloVend-DatiBolleAperteRilasciate.order no_]),0,[PaiaInBollaInviatoWMSps]) AS PairsReadyForShippingInviatoWMSps, IIf(IsNull([qsoloVend-DatiBolleAperteRilasciate.order no_]),0,[quantitainbollaInviatoWMSps]) AS QuantityReadyForShippingInviatoWMSps, IIf(IsNull([qsoloVend-DatiBolleAperteRilasciate.order no_]),0,IIf(Val([quantity])>0,Nz([quantitainbollaInviatoWMSps])/Val([quantity])*[ValueSold],0)) AS ValueReadyForShippingInviatoWMSps, IIf(IsNull([qsoloVend-DatiBolleAperteRilasciate.order no_]),0,[PaiaInBollaEvasoWMSps]) AS PairsReadyForShippingEvasoWMSps, IIf(IsNull([qsoloVend-DatiBolleAperteRilasciate.order no_]),0,[quantitainbollaEvasoWMSps]) AS QuantityReadyForShippingEvasoWMSps, IIf(IsNull([qsoloVend-DatiBolleAperteRilasciate.order no_]),0,IIf(Val([quantity])>0,Nz([quantitainbollaEvasoWMSps])/Val([quantity])*[ValueSold],0)) AS ValueReadyForShippingEvasoWMSps, [Sales Header].[Payment Terms Code], [Sales Header].[Payment Method Code], [Sales Header].[Invoice Discount Calculation] AS CalcoloScontoFattura, Val([Sales Header.Invoice Discount Value]) AS ScontoFattura, IIf([Consignment]=True,"SI","NO") AS ContoVendita, Val([Right on Return _]) AS PercentualeDirittoAlReso, [Sales Header].Note, [Sales Header].[Campaign No_], [Sales Header].[event code], Val([Sales Line.Line Discount _]) AS ScontoRiga, Val([Sales Line.Discount 1 _]) AS Sconto1Riga, Val([Sales Line.Discount 2 _]) AS Sconto2Riga, Val([Sales Line.Discount 3 _]) AS Sconto3Riga, IIf([Anomalous]=1,"X","") AS Anomalo, IIf([Not Anomalous]=1,"X","") AS NonAnomalo, [Sales Header].[Anomalous Date], IIf([Checked]=1,"X","") AS Verificato, [Sales Header].[Checked Date], [Sales Header].[Budget No_], [Sales Header].[Course Date] AS DataDecorrenza, [Sales Header].[KIMO_FASHION SO No_] AS KimoOrder, [Sales Header].[Shipment Method Code] AS ShipmentMethodCode, [Shipment Method].Description AS ShipmentMethodDescription, [Sales Header].[Selling Season Code] AS [SEASON CODE], [Sales Header].[Transport Reason Code], [Transport Reason Code].Description AS TransportReasonCodeDescription, [Sales Line].[Location Code], [Sales Header].[Shipping Agent Code], [Sales Header].[Shipping Agent Service Code], dateprenotazionipervendite.[Date Reservation], [Sales Header].[Fast Shipping], [Sales Header].[Commission Group Code] AS CommissionGroupCodeOrder, [Sales Header].[Geographical Zone] AS GeographicalZoneFromOrder, [Geographical Zone].Description AS GeographicalZoneDescriptionFromOrder, [Budget Header].[Budget Area], [Sales Line].[Model Cross Reference], [Sales Header].[shortcut dimension 2 code] AS [trademark code]
FROM (((((((((((((([Sales Line] INNER JOIN [Sales Header] ON ([Sales Line].[Document Type] = [Sales Header].[Document Type]) AND ([Sales Line].[Document No_] = [Sales Header].No_)) LEFT JOIN Salesperson_Purchaser ON [Sales Header].[Salesperson Code] = Salesperson_Purchaser.Code) INNER JOIN [Variable Code] ON ([Sales Line].[Constant Assortment Var_Grp_] = [Variable Code].[Variable Group]) AND ([Sales Line].[Constant Variable Code] = [Variable Code].[Variable Code])) LEFT JOIN [qsoloVend-DatiBolleAperteRilasciate] ON ([Sales Line].[Line No_] = [qsoloVend-DatiBolleAperteRilasciate].[Order Line No_]) AND ([Sales Line].[Document No_] = [qsoloVend-DatiBolleAperteRilasciate].[Order No_])) LEFT JOIN [Shipment Method] ON [Sales Header].[Shipment Method Code] = [Shipment Method].Code) LEFT JOIN Salesperson_Purchaser AS Salesperson_Purchaser_1 ON [Sales Header].[Area Manager Code] = Salesperson_Purchaser_1.Code) LEFT JOIN Salesperson_Purchaser AS Salesperson_Purchaser_2 ON [Sales Header].[Subject 1] = Salesperson_Purchaser_2.Code) LEFT JOIN Salesperson_Purchaser AS Salesperson_Purchaser_3 ON [Sales Header].[Subject 2] = Salesperson_Purchaser_3.Code) LEFT JOIN [Transport Reason Code] ON [Sales Header].[Transport Reason Code] = [Transport Reason Code].Code) LEFT JOIN dateprenotazionipervendite ON ([Sales Line].[Document No_] = dateprenotazionipervendite.[Sales Document No_]) AND ([Sales Line].[Line No_] = dateprenotazionipervendite.[Sales Line No_])) LEFT JOIN [Geographical Zone] ON [Sales Header].[Geographical Zone] = [Geographical Zone].Code) LEFT JOIN [Budget Header] ON [Sales Header].[Budget No_] = [Budget Header].No_) LEFT JOIN [Sales Header Extension] ON ([Sales Header].No_ = [Sales Header Extension].[Document No_]) AND ([Sales Header].[Document Type] = [Sales Header Extension].[Document Type])) LEFT JOIN Salesperson_Purchaser AS Salesperson_Purchaser_4 ON [Sales Header Extension].[Subject 3] = Salesperson_Purchaser_4.Code) LEFT JOIN Salesperson_Purchaser AS Salesperson_Purchaser_5 ON [Sales Header Extension].[Subject 4] = Salesperson_Purchaser_5.Code
WHERE (((IIf([Sales Line.Document Type]=1,"SALES",IIf([Sales Line.Document Type]=5,"RETURNS","")))<>"") AND (([Sales Line].Type)=20 Or ([Sales Line].Type)=19));

